code.C:
#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int a, b;
        scanf("%d %d", &a, &b);
        if (a < b) printf("%d\n", b - a);
        else if (a > b) printf("%d\n", a - b);
        else printf("0\n");
    }
    return 0;
}

