code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let t;
readline.on('line', line => {
    if (i === 0) {
        t = parseInt(line);
        i++;
    } else {
        let [a, b] = line.split(' ').map(num => parseInt(num));
        if (a < b) console.log(b - a);
        else if (a > b) console.log(a - b);
        else console.log(0);
        i++;
        if (i > t) readline.close();
    }
});

